class CifarLoader:
    def __init__(self, path, train=True, batch_size=500, aug=None):
        from pathlib import Path

        data_path = Path(path) / ("train.pt" if train else "test.pt")
        if not data_path.exists():
            dset = torchvision.datasets.CIFAR10(path, download=True, train=train)
            images = torch.tensor(dset.data)
            labels = torch.tensor(dset.targets)
            torch.save({"images": images, "labels": labels, "classes": dset.classes}, data_path)

        def _safe_load_cached(path_obj):
            load_kwargs = {"map_location": torch.device("cpu")}
            try:
                return torch.load(path_obj, weights_only=True, **load_kwargs)
            except TypeError:
                return torch.load(path_obj, **load_kwargs)

        def _build_and_store_cache(path_obj):
            dset = torchvision.datasets.CIFAR10(str(path_obj.parent), download=True, train=train)
            payload = {
                "images": torch.tensor(dset.data),
                "labels": torch.tensor(dset.targets),
                "classes": list(dset.classes),
            }
            torch.save(payload, path_obj)
            return payload

        data = _safe_load_cached(data_path)
        if not isinstance(data, dict) or "images" not in data or "labels" not in data:
            data = _build_and_store_cache(data_path)

        images = data["images"]
        labels = data["labels"]
        classes = data.get("classes")

        if not isinstance(images, torch.Tensor) or not isinstance(labels, torch.Tensor):
            data = _build_and_store_cache(data_path)
            images = data["images"]
            labels = data["labels"]
            classes = data["classes"]

        if images.ndim != 4 or images.shape[-1] != 3:
            raise ValueError(f"Unexpected CIFAR image tensor shape: {tuple(images.shape)}")
        if labels.ndim != 1 or labels.shape[0] != images.shape[0]:
            raise ValueError(f"Unexpected CIFAR label tensor shape: {tuple(labels.shape)} for images {tuple(images.shape)}")
        if classes is None:
            classes = [str(i) for i in range(10)]

        self.images = images.cuda(non_blocking=True)
        self.labels = labels.to(device=self.images.device, dtype=torch.long, non_blocking=True)
        self.classes = classes
        self.images = (self.images.half() / 255).permute(0, 3, 1, 2).contiguous(memory_format=torch.channels_last)

        self.normalize = T.Normalize(CIFAR_MEAN, CIFAR_STD)
        self.proc_images = {}
        self.epoch = 0
        self.aug = aug or {}
        for key in self.aug:
            if key not in {"flip", "translate"}:
                raise ValueError(f"Unrecognized augmentation key: {key}")
        self.batch_size = batch_size
        self.drop_last = train
        self.shuffle = train

    def __len__(self):
        if self.drop_last:
            return len(self.images) // self.batch_size
        return ceil(len(self.images) / self.batch_size)

    def __iter__(self):
        if self.epoch == 0:
            images = self.proc_images["norm"] = self.normalize(self.images)
            if self.aug.get("flip", False):
                images = self.proc_images["flip"] = batch_flip_lr(images)
            pad = self.aug.get("translate", 0)
            if pad > 0:
                self.proc_images["pad"] = F.pad(images, (pad,) * 4, "reflect")

        if self.aug.get("translate", 0) > 0:
            images = batch_crop(self.proc_images["pad"], self.images.shape[-2])
        elif self.aug.get("flip", False):
            images = self.proc_images["flip"]
        else:
            images = self.proc_images["norm"]

        if self.aug.get("flip", False) and self.epoch % 2 == 1:
            images = images.flip(-1)

        self.epoch += 1
        indices = (torch.randperm if self.shuffle else torch.arange)(len(images), device=images.device)
        for i in range(len(self)):
            idxs = indices[i * self.batch_size : (i + 1) * self.batch_size]
            yield images[idxs], self.labels[idxs]
